// Filter for files modified in the last 6 hours and 10 minutes
// (slightly longer than poll interval to avoid edge-case misses)
const items = $input.all();
const now = new Date();
const cutoffMs = 6 * 60 * 60 * 1000 + 10 * 60 * 1000; // 6h 10min

const recent = items.filter(item => {
  const file = item.json;
  const modTime = new Date(file.modifiedTime || file.createdTime || 0);
  return (now - modTime) < cutoffMs;
});

if (recent.length === 0) {
  // No recent changes — return a sentinel to signal 'skip'
  return [{ json: { _noChanges: true, checkedAt: now.toISOString(), totalFiles: items.length } }];
}

// Build a readable summary
const lines = recent.map(item => {
  const f = item.json;
  const modTime = new Date(f.modifiedTime || f.createdTime);
  const isNew = (now - new Date(f.createdTime)) < cutoffMs;
  const action = isNew ? '🆕' : '✏️';
  const timeStr = modTime.toLocaleTimeString('de-AT', { hour: '2-digit', minute: '2-digit' });
  // Strip Google Docs MIME type to readable
  const typeMap = {
    'application/vnd.google-apps.document': 'Doc',
    'application/vnd.google-apps.spreadsheet': 'Sheet',
    'application/vnd.google-apps.presentation': 'Slides',
    'application/vnd.google-apps.folder': 'Folder',
    'application/pdf': 'PDF',
    'application/vnd.openxmlformats-officedocument.presentationml.presentation': 'PPTX',
    'application/vnd.openxmlformats-officedocument.wordprocessingml.document': 'DOCX',
    'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet': 'XLSX'
  };
  const type = typeMap[f.mimeType] || 'File';
  const link = f.webViewLink ? ` — [open](${f.webViewLink})` : '';
  return `${action} *${f.name}* (${type}) — ${timeStr}${link}`;
});

return [{
  json: {
    _noChanges: false,
    changeCount: recent.length,
    summary: lines.join('\n'),
    checkedAt: now.toISOString()
  }
}];
